UPDATE `custom_settings` SET `value` = '\"{% if this|is_model:\\\"Accounts\\\" %}\\n{\\n    \\\"id\\\": \\\"{{this.id}}\\\",\\n    \\\"record_type_id\\\":\\\"{{this.record_type_id}}\\\",\\n    \\\"enable_view\\\": {% if this.enable_view %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_update\\\": {% if this.enable_update %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_transform\\\": {% if this.enable_transform %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    {% if this.enable_transform %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_appliable\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f(\\u53ef\\u7533\\u8bf7)\\\"\\n        },\\n    {% elif this.with_position_by_me %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_with_position_by_me\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\\"\\n        },\\n    {% elif this.with_position_by_other %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_with_position_by_other\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\\"\\n        },\\n    {% elif this.without_position_by_me %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_without_position_by_me\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\\"\\n        },\\n    {% elif this.without_position_by_other %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_without_position_by_other\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\\"\\n        },\\n    {% elif this.without_position_by_null %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_without_position_by_null\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\\"\\n        },\\n    {% endif %}\\n    \\\"display\\\": [\\n        \\\"{{this.name}}\\\",\\n        \\\"{{this.hospital.name}}\\\",\\n        \\\"{{this.standard_department.label}}\\\",\\n        {% if this.professional_title %}\\n        \\\"{{this.professional_title.label}}\\\"\\n        {% else %}\\n        null\\n        {% endif %}\\n    ]\\n}\\n{% elif this|is_model:\\\"DCRs\\\" %}\\n{\\n    \\\"id\\\": \\\"{{this.id}}\\\",\\n    \\\"record_type_id\\\":\\\"{{this.record_type_id}}\\\",\\n    \\\"state_id\\\":\\\"{{this.state_id}}\\\",\\n    \\\"enable_view\\\": {% if this.enable_view %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_update\\\": {% if this.enable_update %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_transform\\\": {% if this.enable_transform %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"professional_in_dcr_by_me\\\",\\n        \\\"label\\\": \\\"\\u533b\\u751f\\u7533\\u8bf7\\u4e2d\\\"\\n    },\\n    {% if this.enable_view %}\\n        \\\"type\\\": {\\n            \\\"name\\\": \\\"professional_in_dcr_by_me\\\",\\n            \\\"label\\\": \\\"\\u533b\\u751f\\u7533\\u8bf7\\u4e2d\\\"\\n        },\\n    {% else %}\\n        \\\"type\\\": {\\n            \\\"name\\\": \\\"professional_in_dcr\\\",\\n            \\\"label\\\": \\\"\\u533b\\u751f\\u4ed6\\u4eba\\u7533\\u8bf7\\u4e2d\\\"\\n        },\\n    {% endif %}\\n    \\\"display\\\": [\\n        \\\"{{this.name}}\\\",\\n        \\\"{{this.hospital.name}}\\\",\\n        \\\"{{this.standard_department.name}}\\\",\\n        {% if this.professional_title %}\\n        \\\"{{this.professional_title.label}}\\\"\\n        {% else %}\\n        null\\n        {% endif %}\\n    ]\\n}\\n{% elif this|is_model:\\\"Speakers\\\" %}\\n{\\n\\\"record_type_id\\\": \\\"{{this.record_type_id}}\\\",\\n    \\\"id\\\": \\\"{{this.id}}\\\",\\n    \\\"state_id\\\":\\\"{{this.state_id}}\\\",\\n    \\\"enable_view\\\": {% if this.enable_view %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_update\\\": {% if this.enable_update %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_transform\\\": {% if this.enable_transform %} {{\\\"true\\