ecord_type_id}}\\\",\\n    \\\"enable_view\\\": {% if this.enable_view %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_update\\\": {% if this.enable_update %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    \\\"enable_transform\\\": {% if this.enable_transform %} {{\\\"true\\\"}} {% else %} {{\\\"false\\\"}}{% endif %},\\n    {% if this.enable_view %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"dcr_by_me\\\",\\n        \\\"label\\\": \\\"\\u8bb2\\u8005\\u6b63\\u5728\\u7533\\u8bf7\\u4e2d\\\"\\n    },\\n    {% else %}\\n    \\\"type\\\": {\\n        \\\"name\\\": \\\"dcr_by_others\\\",\\n        \\\"label\\\": \\\"\\u8bb2\\u8005\\u4ed6\\u4eba\\u7533\\u8bf7\\u4e2d\\\"\\n    },\\n    {% endif %}\\n    \\\"display\\\": [\\n        \\\"{{this.name}}\\\",\\n        {% if this.hospital_institution %}\\n        \\\"{{this.hospital_institution.name}}\\\",\\n        {% elif this.non_hospital_institution %}\\n         \\\"{{this.non_hospital_institution}}\\\",\\n        {% else %}\\n        \\\"\\\",\\n        {% endif %}\\n        {% if this.department_id %}\\n        \\\"{{this.department.label}}\\\",\\n        {% else %}\\n        null,\\n         {% endif %}\\n        {% if this.professional_title_id %}\\n        \\\"{{this.professional_title.label}}\\\",\\n        {% else %}\\n        null,\\n         {% endif %}\\n       {% if this.level_id %}\\n        \\\"{{this.level.label}}\\\"\\n        {% else %}\\n        null\\n         {% endif %}\\n    ]\\n}\\n{% endif %}\\n\"' WHERE (`key` = 'speaker_dcr_search_result');

