UPDATE `page_lists` SET `external_condition` = 'from django.db import models as djm\nfrom orionbase.common import models\n\ndef get_condition(metadata_user, page_list):\n    # 选择下属岗位\n    # SFE的场合显示所有数据\n    role_id = models.OrionUsers.objects.get(user_id=metadata_user.user_id).role.id\n    root_position = []\n    if role_id == \'53de9674-1da3-11e6-ac97-5cc5d4b57137\':\n        return djm.Q()\n    ids = []\n    _ids = list(models.UserPositionHistories.objects.filter(user_id=metadata_user.user_id,version__is_active=1).values_list(\'position_id\', flat=True))\n    shares = list(models.SharingRules.advance_objects.filter(\n            to_position__in=_ids, object__name=\'sales_target\'\n        ).values_list(\'from_position_id\', flat=True))\n    _ids = _ids + shares\n    for id in _ids:\n        sub_ids = list(models.PositionHistories.objects.filter(org_path__contains=id,version__is_active=1).values_list(\'org_position_id\', flat=True))\n        ids = _ids + sub_ids\n    ids = list(set(ids))\n    res = []\n    for p in models.PositionHistories.objects.filter(org_position_id__in=ids).only(\'org_position_id\', \'org_path\'):\n        real_path = (p.org_path or \'/\') + str(p.org_position_id) + \'/\'\n        res.append(real_path)\n    return djm.Q(position_path__in=res)\n' WHERE (`id` = '70fd1977-49ad-451a-827d-d41b80caaad7');

